// AgentServiceHandler is an implementation of the gitpod.v1.AgentService service.
type AgentServiceHandler interface {
	// Lists all agents matching the specified criteria.
	//
	// Use this method to find and monitor agents across your organization.
	// Results are ordered by their creation time with the newest first.
	//
	// ### Examples
	//
	// - List all agents:
	//
	//	Retrieves all agents with pagination.
	//
	//	```yaml
	//	pagination:
	//	  pageSize: 10
	//	```
	ListAgents(context.Context, *connect.Request[v1.ListAgentsRequest]) (*connect.Response[v1.ListAgentsResponse], error)
	// Gets details about a specific agent including description,
	// and required models.
	//
	// Use this method to:
	// - Check if an agent is defined correctly
	// - Understand which models are required for this agent
	//
	// ### Examples
	//
	// - Get agent details:
	//
	//	```yaml
	//	agentId: "07e03a28-65a5-4d98-b532-8ea67b188048"
	//	```
	GetAgent(context.Context, *connect.Request[v1.GetAgentRequest]) (*connect.Response[v1.GetAgentResponse], error)
	// Creates a new agent.
	//
	// Use this method to:
	// - Define new agents with custom prompts and tools
	CreateAgent(context.Context, *connect.Request[v1.CreateAgentRequest]) (*connect.Response[v1.CreateAgentResponse], error)
	// Updates an existing agent.
	//
	// Use this method to:
	// - Modify agent configuration
	// - Update prompts or required tools
	UpdateAgent(context.Context, *connect.Request[v1.UpdateAgentRequest]) (*connect.Response[v1.UpdateAgentResponse], error)
	// Deletes an agent.
	//
	// Use this method to:
	// - Remove custom agents
	DeleteAgent(context.Context, *connect.Request[v1.DeleteAgentRequest]) (*connect.Response[v1.DeleteAgentResponse], error)
	// Starts (or triggers) an agent run using a provided agent.
	//
	// Use this method to:
	// - Launch an agent based on a known agent
	//
	// ### Examples
	//
	// - Start an agent with a project ID:
	//
	//	```yaml
	//	agentId: "b8a64cfa-43e2-4b9d-9fb3-07edc63f5971"
	//	codeContext:
	//	  projectId: "2d22e4eb-31da-467f-882c-27e21550992f"
	//	```
	StartAgent(context.Context, *connect.Request[v1.StartAgentRequest]) (*connect.Response[v1.StartAgentResponse], error)
	// Lists all agent runs matching the specified filter.
	//
	// Use this method to track multiple agent runs and their associated resources. Results are ordered by their creation time with the newest first.
	//
	// ### Examples
	//
	// - List agent runs by agent ID:
	//
	//	```yaml
	//	filter:
	//	  agentIds: ["b8a64cfa-43e2-4b9d-9fb3-07edc63f5971"]
	//	pagination:
	//	  pageSize: 10
	//	```
	ListAgentExecutions(context.Context, *connect.Request[v1.ListAgentExecutionsRequest]) (*connect.Response[v1.ListAgentExecutionsResponse], error)
	// Gets details about a specific agent run, including its metadata, specification,
	// and status (phase, error messages, and usage statistics).
	//
	// Use this method to:
	// - Monitor the run's progress
	// - Retrieve the agent's conversation URL
	// - Check if an agent run is actively producing output
	//
	// ### Examples
	//
	// - Get agent run details by ID:
	//
	//	```yaml
	//	agentExecutionId: "6fa1a3c7-fbb7-49d1-ba56-1890dc7c4c35"
	//	```
	GetAgentExecution(context.Context, *connect.Request[v1.GetAgentExecutionRequest]) (*connect.Response[v1.GetAgentExecutionResponse], error)
	// Deletes an agent run.
	//
	// Use this method to:
	// - Clean up agent runs that are no longer needed
	//
	// ### Examples
	//
	// - Delete an agent run by ID:
	//
	//	```yaml
	//	agentExecutionId: "6fa1a3c7-fbb7-49d1-ba56-1890dc7c4c35"
	//	```
	DeleteAgentExecution(context.Context, *connect.Request[v1.DeleteAgentExecutionRequest]) (*connect.Response[v1.DeleteAgentExecutionResponse], error)
	// Sends user input to an active agent run.
	//
	// This method is used to provide interactive or conversation-based input
	// to an agent. The agent can respond with output blocks containing
	// text, file changes, or tool usage requests.
	//
	// ### Examples
	//
	// - Send a text message to an agent:
	//
	//	```yaml
	//	agentExecutionId: "6fa1a3c7-fbb7-49d1-ba56-1890dc7c4c35"
	//	userInput:
	//	  text:
	//	    content: "Generate a report based on the latest logs."
	//	```
	SendToAgentExecution(context.Context, *connect.Request[v1.SendToAgentExecutionRequest]) (*connect.Response[v1.SendToAgentExecutionResponse], error)
	// Creates a token for conversation access with a specific agent run.
	//
	// This method generates a temporary token that can be used to securely
	// connect to an ongoing agent conversation, for example in a web UI.
	//
	// ### Examples
	//
	// - Create a token to join an agent run conversation in a front-end application:
	//
	//	```yaml
	//	agentExecutionId: "6fa1a3c7-fbb7-49d1-ba56-1890dc7c4c35"
	//	```
	CreateAgentExecutionConversationToken(context.Context, *connect.Request[v1.CreateAgentExecutionConversationTokenRequest]) (*connect.Response[v1.CreateAgentExecutionConversationTokenResponse], error)
	// Stops an active agent execution.
	//
	// Use this method to:
	// - Stop an agent that is currently running
	// - Prevent further processing or resource usage
	//
	// ### Examples
	//
	// - Stop an agent execution by ID:
	//
	//	```yaml
	//	agentExecutionId: "6fa1a3c7-fbb7-49d1-ba56-1890dc7c4c35"
	//	```
	StopAgentExecution(context.Context, *connect.Request[v1.StopAgentExecutionRequest]) (*connect.Response[v1.StopAgentExecutionResponse], error)
	// Updates an agent execution's spec.
	//
	// Use this method to:
	// - Set or update loop conditions on an agent execution
	UpdateAgentExecution(context.Context, *connect.Request[v1.UpdateAgentExecutionRequest]) (*connect.Response[v1.UpdateAgentExecutionResponse], error)
	// Reports outputs for an agent execution.
	//
	// This method allows agents to report key-value outputs during execution.
	// Similar to task execution outputs, but with typed values for structured data.
	// Outputs are merged with any existing outputs. The API automatically infers
	// the type (int, float, bool, or string) from the value.
	//
	// Use this method to:
	// - Record execution outcomes and metrics
	// - Track test results, coverage, or success indicators
	// - Store any execution-related data as key-value pairs
	//
	// Type inference rules:
	// - "true" or "false" → bool
	// - Valid integer (e.g., "42", "-10") → int
	// - Valid float (e.g., "85.5", "3.14") → float
	// - Everything else → string
	//
	// Validation limits (matching task execution outputs):
	// - Keys: 1-128 characters
	// - String values: max 4096 characters
	//
	// ### Examples
	//
	// - Report execution outputs (types will be inferred from string_value):
	//
	//	```yaml
	//	agentExecutionId: "6fa1a3c7-fbb7-49d1-ba56-1890dc7c4c35"
	//	outputs:
	//	  tests_passed:
	//	    stringValue: "42"        # inferred as int
	//	  coverage:
	//	    stringValue: "85.5"      # inferred as float
	//	  success:
	//	    stringValue: "true"      # inferred as bool
	//	  message:
	//	    stringValue: "All tests passed"  # stored as string
	//	```
	ReportAgentExecutionOutputs(context.Context, *connect.Request[v1.ReportAgentExecutionOutputsRequest]) (*connect.Response[v1.ReportAgentExecutionOutputsResponse], error)
	// Emits an activity to the external agent session (e.g., Linear) associated
	// with this agent execution. The backend resolves the session ID from the
	// execution's annotations and uses the org's app token to authenticate.
	EmitAgentSessionActivity(context.Context, *connect.Request[v1.EmitAgentSessionActivityRequest]) (*connect.Response[v1.EmitAgentSessionActivityResponse], error)
	// Improves an agent's prompt.
	//
	// Use this method to:
	// - Enhance the agent's understanding of the user's request
	// - Refine the agent's response to be more accurate and relevant
	ImprovePromptForAgent(context.Context, *connect.Request[v1.ImprovePromptForAgentRequest]) (*connect.Response[v1.ImprovePromptForAgentResponse], error)
	// Creates a token for LLM access with a specific agent run.
	CreateLLMAccessToken(context.Context, *connect.Request[v1.CreateLLMAccessTokenRequest]) (*connect.Response[v1.CreateLLMAccessTokenResponse], error)
	// Lists all MCP integrations.
	//
	// Use this method to retrieve all configured MCP integrations.
	//
	// ### Examples
	//
	// - List all MCP integrations:
	//
	//	```yaml
	//	pagination:
	//	  pageSize: 10
	//	```
	ListMCPIntegrations(context.Context, *connect.Request[v1.ListMCPIntegrationsRequest]) (*connect.Response[v1.ListMCPIntegrationsResponse], error)
	// Creates a token for MCP access.
	//
	// Use this method to generate an access token for MCP integrations.
	CreateMCPAccessToken(context.Context, *connect.Request[v1.CreateMCPAccessTokenRequest]) (*connect.Response[v1.CreateMCPAccessTokenResponse], error)
	// Lists all prompts matching the specified criteria.
	//
	// Use this method to find and browse prompts across your organization.
	// Results are ordered by their creation time with the newest first.
	//
	// ### Examples
	//
	// - List all prompts:
	//
	//	Retrieves all prompts with pagination.
	//
	//	```yaml
	//	pagination:
	//	  pageSize: 10
	//	```
	ListPrompts(context.Context, *connect.Request[v1.ListPromptsRequest]) (*connect.Response[v1.ListPromptsResponse], error)
	// Gets details about a specific prompt including name, description,
	// and prompt content.
	//
	// Use this method to:
	// - Retrieve prompt details for editing
	// - Get prompt content for execution
	//
	// ### Examples
	//
	// - Get prompt details:
	//
	//	```yaml
	//	promptId: "07e03a28-65a5-4d98-b532-8ea67b188048"
	//	```
	GetPrompt(context.Context, *connect.Request[v1.GetPromptRequest]) (*connect.Response[v1.GetPromptResponse], error)
	// Creates a new prompt.
	//
	// Use this method to:
	// - Define new prompts for templates or commands
	// - Set up organization-wide prompt libraries
	CreatePrompt(context.Context, *connect.Request[v1.CreatePromptRequest]) (*connect.Response[v1.CreatePromptResponse], error)
	// Updates an existing prompt.
	//
	// Use this method to:
	// - Modify prompt content or metadata
	// - Change prompt type (template/command)
	UpdatePrompt(context.Context, *connect.Request[v1.UpdatePromptRequest]) (*connect.Response[v1.UpdatePromptResponse], error)
	// Deletes a prompt.
	//
	// Use this method to:
	// - Remove unused prompts
	DeletePrompt(context.Context, *connect.Request[v1.DeletePromptRequest]) (*connect.Response[v1.DeletePromptResponse], error)
}

